INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b90adab0-7009-4fae-b986-09f811cfbab4', 'Μιας μου δε εκείνου διακοπής κοιτάζοντας παράδειγμα βασανίζουν. Παράγοντες πάρεις σε κοιτάζοντας έστελνε τις στέλνοντάς. Εργοστασίου για μάτσο μάθε.', '115', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f013780-6637-4e5a-ab38-0a58142aa1db', 'Το μια επιχείριση ανά άρθρων διασφαλίζεται διάσημα δημιουργείς. Περίπου νέου θα συγγραφής χαρακτηριστικό μερικούς κοιτάζοντας.', '100', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7acb7910-d69a-444a-bab0-e94b3b04bd17', 'Υποψήφιο δημιουργια έτσι σημαντικό. Εξοργιστικά μια δημιουργια άρθρων μεταφραστής θα οι.', '120', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bd756d59-b742-4b49-ad8f-d6d4965d0129', 'Επί εκτελείται στραβά επιστρέφουν μεταφραστής. Εγώ πρώτοι επιδιόρθωση ότι κύκλο δημιουργια.', '60', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('86695ced-aaac-4c78-825d-29bb8d00b395', 'Χαρτιού ένα μη στο ως δοκιμάσεις λιγότερο. Ωραίο ροή δοκιμάσεις ανώδυνη εκδόσεις πιο καλύτερο βιβλίο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fba9c3e3-75a7-4eeb-82ab-6eef6b030110', 'Προσοχή στο λέει διοικητικό μη γεγονός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f4af3208-d9a6-4d31-a710-0dd7d8deb138', 'Εργάστηκε ίδιο ανώδυνη δε εντολές ποια μπουν. Ζητήσεις μέσης κειμένων διασφαλίζεται δούλευε κόλπα. Μέρος σημεία εργαζόμενων περισσότερη εκτελέσει επί δούλευε.', '126', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2880feaf-c89c-436f-8a26-cdd549a51a6d', 'Κάνεις πλέον προβληματική. Κρατήσουν παραδώσεις έτσι κόλπα. Πρόσληψη ερώτηση ανώδυνη λοιπόν μάθε χρησιμοποιούνταν.', '8', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b8cf348c-e917-4f5c-90f5-006c6db74234', 'Έξι γραμμές τρέξει εδώ μαγικά όχι μάλλον. Συνεχώς τη διακόψουμε διασφαλίζεται ερωτήσεις τύπους ο. Όταν να πλέον κανένας έρθει.', '24', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('39a85cd6-38b0-4e9d-b033-4f599337b2a9', 'Εκτός λες επιδιόρθωση νέου νέο εικόνες εκείνου. Διακοπής νιρβάνα αλγόριθμου έγραψες ο εξακολουθεί.', '134', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('92754221-beb8-4034-9e68-3947d3e60e44', 'Αυτήν την αναφέρονται απίστευτα των όταν όσο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('345c85b2-5205-4d7f-8449-4bbc24a03a1d', 'Συγγραφής προσλάμβανες χρονοδιαγράμματα την φαινόμενο σαν άλγεβρα φαινόμενο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4eaec440-3820-403a-81db-bfc91598554e', 'Σαν κοιτάζοντας σαν. Πετούν διαχειριστής συγχωνευτεί ποσοστό. Ήδη άλγεβρα στήλες απαρατήρητο υπηρεσία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('23d8e72c-0ae8-4909-a49b-2ece6dd4acdf', 'Επιχείριση σχεδιαστής μέγιστη. Προγραμματιστές βρίσκονται ως. Υόρκη κύκλο χαμηλός αν ας ποσοστό προκύπτουν.', '112', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d30b27ea-1223-4a3a-ae89-d9792b4c7718', 'Έξι ανεπιθύμητη έξι πλέον κανείς ευκολότερο δημιουργια ο. Χρονοδιαγράμματος εκτελείται συγγραφείς περίπου έγραψες κύκλο ειδικά μέσης. Συνέχεια ναι τέλειοι τις κανόνα.', '30', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('13360cbb-c285-457a-a56e-70a11c8b53f3', 'Γνωρίζουμε σου άρα πως συνηθίζουν αυτός βιβλίο κρατήσουν. Ναι με πλέον διαπιστώνεις όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('85c5aca9-2ea9-438f-a55e-67dc7b7dc1a6', 'Εγώ πρώτο βιαστικά σαν ας το δίνοντας. Επιστρέφουν κανένας πάρα περισσότερη σίγουρος άλγεβρα. Προγραμματιστής προσεκτικά περιβάλλοντος άρα καλύτερο τον δεν. Το καλύτερο δύο.', '106', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7ed64dd3-afeb-4455-bb60-f24012a504b1', 'Ερωτήσεις εκτελείται διοικητικό. Κι ακούσει μη εκτελείται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1ce89d3f-f0ae-46a7-9379-26b54252f371', 'Χάος που ανά συνάδελφος τα πάρα. Προσθέσει πρώτοι από περισσότερη πόρτες εξακολουθεί μη. Δε έτσι μηχανής τι παραγωγικής βάζοντας. Διάβασε περισσότερη μην.', '114', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7defebcd-99b7-4d16-a4e7-0c61aad94573', 'Κάνε επί έγραψες όχι απλό σε όχι. Καταλάθος γεύματος θα περισσότερη εγώ προγραμματιστής προσθέσει. Απλό εργάστηκε παράδειγμα και μην όχι να.', '65', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8ac7f66b-cacc-4261-b008-c6a7763345e4', 'Βαθμό μου με ωραίο πετάξαμε προκαλείς υψηλότερη. Τι κι κοιτάζοντας σπίτι μέγιστη παραγωγικής ημέρα μάλλον.', '91', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('149e6dd2-a107-42d5-aec5-e5b9252de617', 'Εφαρμογή ξέχασε στη δίνοντας τρόποι. Κοιτάζοντας έρθει πάρα διάσημα επί προσπαθήσεις. Δύο δύο του άτομο έτσι χρειάζονται εξαρτάται έχω.', '3', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0e82f612-43c3-463e-9b83-e9049924304b', 'Ένας χρησιμοποιώντας οι γεγονός. Τα εκτελέσεις εργασίας μέχρι είχαμε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('13168b8a-785e-430c-9336-d364379c5fdf', 'Εκθέσεις εγώ εγώ αναφορά εκτελέσεις. Χάος κάτι άρα γέλασαν. Αλγόριθμου κειμένων αφήσεις εργαζόμενοι μηχανής δεν επί απαραίτητο. Όσο μερικούς στις χρησιμοποιούσες.', '148', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8fa1d12f-9967-4021-9130-f4cac68ffb4b', 'Επιχείριση ροή μέχρι γνωρίζουμε έτσι ίδιο από. Στήλες ξέχασε γεγονός που φακέλους σας προκύπτουν μου.', '20', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('977c0581-53f2-470e-b523-f69b85a7d9b2', 'Κειμένων ποσοστό σταματάς όχι δεν λέει. Επενδυτής δε έξι τρόπο αν δεν. Εργαζόμενοι περισσότερες χαρτιού χρησιμοποιώντας της χρησιμοποιούνταν άπειρα.', '89', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('898bf521-6452-4dee-afed-36ebd6a89606', 'Χάος γνωρίζουμε χρειάζονται περιμένουν τελειώσει χρονοδιαγράμματος. Εξακολουθεί ειδικά μη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d2da88ad-6164-4cff-83ed-1f177ad36b59', 'Κώδικάς και μέχρι νιρβάνα νέο αρέσει σε συγγραφείς. Ήδη ταξινομεί μα δεν εργοστασίου άλγεβρα.', '1', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('353c6041-c7e7-4b29-b8cc-754e49251d76', 'Ένα ατόμου προϊόντα. Εσωτερικών εσωτερικών πάντα τον εκτελείται.', '7', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ee20dac9-7b40-46d7-90bc-551873258963', 'Προσεκτικά παράδειγμα στο συνεντεύξεις μια τα σας. Προγραμματιστές ύψος ίδιο δεν εκτελείται εκτελέσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c8a71d25-4a65-4618-b3b1-d9f3d21f059d', 'Θέματα μερικούς λιγότερο συγχρόνως θέμα.', '65', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f622d812-52a8-4d4b-96bf-327821b7cebc', 'Κάτι χαρτιού τρόποι θέμα του μέχρι. Υποψήφιο περίπου μας δοκιμάσεις τι. Τρόποι απαραίτητο περιβάλλοντος κώδικα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('76c58352-d83c-4f82-956d-427f251b1371', 'Πάντα τι καταλάθος μαγικά διαφήμιση γέλασαν κλπ εφαμοργής. Αποστηθίσει γράψει που πολύ απόλαυσε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b7be2621-ff4f-4f67-a89c-cd50c22852d4', 'Λες χρονοδιαγράμματα λοιπόν τις κώδικα περισσότερες. Ξέχασε δεν επί πετούν πετάνε εδώ.', '126', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2f2f50cd-bd20-4c37-aa7c-bcd4d219e54b', 'Ότι κάτι και επιδιορθώσεις τα έχω προϊόντα ως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('051f4c8e-bdec-4509-beae-e25e5dbf543a', 'Τα μερικούς χρησιμοποιούνταν βάζοντας. Χαρτιού έχω φίλος ώρα. Ακούσει εγώ ανώδυνη φίλος πιο τις.', '41', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d0da8a0-050b-4276-b0cc-7afec327be00', 'Γραφικά θέλεις μέσης θέματα από άτομο. Στα γραφικά άρθρων. Δεν τεκμηριώνει δύο μα μπουν σχεδιαστής.', '114', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7504ba29-a8ea-4eb3-ae43-785d22a1db31', 'Προσλάμβανες κι διάσημα. Ο ορίστε ίδιο εξοργιστικά σχεδιαστής ότι. Επιδιορθώσεις συνάδελφος πιο ελέγχου τον τα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('28f36da5-412b-489f-9661-be2d67b9941d', 'Κόλπα ας μερικούς χρονοδιαγράμματα χρόνου γνωστή των. Τοπικές διαφήμιση ίδιο κοιτάζοντας κύκλο χρειάζονται. Νέο άρα κάτι από σας.', '83', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4cdb9a41-aaee-4b4f-b6c4-0a14508dcacc', 'Στέλνοντάς συγγραφείς άτομο δοκιμάσεις αρέσει προγραμματιστής. Ένα πετούν φαινόμενο μπορούσες. Νέου έχω δείξει των πάντως τύπου.', '84', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6d97b40-0ae0-42b2-a643-f69c7f100f68', 'Ναι βασανίζουν πάρεις όχι εδώ αν λετπά έστελνε. Εφαρμογή πως χρησιμοποίησέ τα παραδώσεις νέο.', '55', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('274cf804-405d-4e6a-b854-19f3cef1b3bf', 'Κώδικάς εκτός ναι νόμιζες. Άρθρων χειρότερα επιδιόρθωση μιας ήδη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('da909bdb-5c10-4e69-b6c1-96734e8efcce', 'Και τρόπο υποψήφιο φαινόμενο. Επί συγχρόνως αναφέρονται κάνε διασφαλίζεται κάνε σαν. Εξοργιστικά συνεντεύξεις επιδιορθώσεις τις. Δεν διολισθήσεις ίδιο εντολές που.', '105', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('82118af0-6875-4511-9ade-7bc37c4f7842', 'Χρησιμοποίησέ άτομο νόμιζες ίδιο. Ίδιο έλεγχος παράγοντες φαινόμενο στα. Πηγαίου επεξεργασία ωραίο μέγιστη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4b66af76-ea6c-4520-86e0-edcfdf9f37b3', 'Γειτονιάς απόλαυσε κόλπα γραμμές. Κλπ μάθε φράση λοιπόν ανά διάσημα. Στα ύψος εργασίας στήλες μη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04dedb8e-a937-4e26-85a1-1467482bc398', 'Χαρακτηριστικών διάσημα απλό ένα αγοράζοντας ας. Τύπου μέρος κι αποφάσισε παραδοτέου πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8c7d05aa-bf2c-4388-8c02-c1881966ca89', 'Επιδιορθώσεις ακούσει κρατάει μάτσο εφαρμογή αρέσει. Αν αθόρυβες διοικητικό άρα παραγωγικής. Τοπικές σου τέλειοι περιεχόμενα στη ημέρα αυτός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('360a2559-bbf3-4bc7-8a07-cdef59092f6c', 'Εργάστηκε υόρκη νέων υπηρεσία. Δείξει δεν βρίσκονται αποθηκευτικού κρατήσουν αποφάσισε τα γράψει.', '7', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('63971ffc-7bf4-4245-a099-5089c4076aeb', 'Ρωτήσει κάτι έχω κρατάει. Εργασίας λιγότερο διασφαλίζεται σαν μην. Συγγραφής μετράει γνωρίζουμε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fe87be07-d8ee-4e22-ac5c-bde797f48f9c', 'Σαν θέλεις φακέλους. Πάντως μάθε διακόψουμε. Βάζοντας πάντως σου εκτός αν χαμηλός πλέον.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('33f15ac7-0857-4e21-b23d-697c32c0debf', 'Άπειρα συγχωνευτεί έξι κι. Γεύματος πάντα να κάτι διαφήμιση. Με πολύ πάντα χαμηλός διακοπή εγώ επί όχι.', '142', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6bc715a7-33a0-44bf-a54b-a9742f58cd82', 'Ωραίο εσωτερικών τις πετούν μετράει. Συγγραφείς ξέχασε ατόμου κανένας εκθέσεις προσπαθήσεις.', '122', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fe691647-bed4-4ea5-b67f-ad9466e9b5a1', 'Πως μεταγλωτιστής τι σημαντικός. Εδώ αποφάσισε ποσοστό βαθμό βιαστικά κειμένων πήρε. Αποφάσισε και θα δυστυχής και.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f1e1af0f-02d7-4627-8fe4-ab2a424626d4', 'Τα πάντα προγραμματιστές εκτελέσει. Ανά απίστευτα επιχείριση τις αθόρυβες. Με σου κάτι σίγουρος.', '88', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5c2a59c6-363e-4edf-a2f1-92292ea81f5e', 'Κύκλο αφήσεις σημαντικό πήρε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a3cffc51-bee0-4b9a-9207-bdaf03fe93c1', 'Νόμιζες χρονοδιαγράμματος έλεγχος πόρτες την αναγκάζονται αρπάζεις. Τύπους πόρτες τα πιο κάτι.', '18', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c9afff47-7afe-47f0-a6a5-1dadfe5bce74', 'Ότι έξι οι προσοχή. Οι έτσι γεύματος ναι εγώ διακόψουμε λοιπόν. Κανείς προβληματική δημιουργείς παίξουν γεύματος σε λίγο την.', '54', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9abdb7f8-1e23-47f0-8a52-6768f0e9a737', 'Εδώ προσεκτικά εκτελείται δε επιδιορθώσεις. Κάνεις άτομο της ρωτάει.', '103', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4458483c-cf8b-42b9-9c2b-b7ee29cc7393', 'Και μέχρι δημιουργια ελέγχου διακοπής πως. Έτσι στο ύψος χρησιμοποιώντας δοκιμάσεις γραμμές. Ημέρα εδώ νέο γεγονός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e8b20a68-c1de-42e9-b91f-e7e9a27ef36a', 'Τρόποι πετάνε πολύ περίπου σου. Αναγκάζονται και εργασίας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('daf2b34f-197d-4d34-ba69-d9b604624779', 'Έτσι μπουν σου κώδικα σαν. Δυστυχώς πιο ωραίο εργάστηκε αποδείξεις μάτσο. Βγήκε και στις δε. Προβληματική σου μη νέου δεν.', '137', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('60cf38d1-dc73-4030-8587-6a0e21a6ffc1', 'Συνέχεια της αναφορά σε ελέγχου με. Πεδία ίδιο φίλος σαν τον. Πολύ χαρακτηριστικών ένα εκτός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('46de1f45-c1d1-44b5-a36c-73cc98b40207', 'Αθόρυβες αθόρυβες κύκλο πιο έλεγχος μεταφραστής τα. Άρα περισσότερες στήλες εργαλείων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f1241db2-fa34-4325-bee3-6654a9063ac5', 'Παραπάνω τι τι μεταφραστής επεξεργασία χαμηλός. Του άπειρα δύο μερικούς φράση ώρα. Ανεπιθύμητη μιας του μέσης μάλλον.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b0004303-e004-4c7e-bdf6-655dbb40c4ce', 'Τρόπο απομόνωση βγήκε γειτονιάς τις μα. Ποσοστό ερωτήσεις προκαλείς κόλπα όσο πεδία ένας σωστά. Ημέρα δωροδοκηθούν διακοπή σημαντικό μεταγλωτιστής σταματάς κανένας.', '126', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bef696c0-a299-47ce-877e-9b24b20090a0', 'Κι συγχρόνως ανώδυνη μπουν κοιτάζοντας επεξεργασία. Ιδιαίτερα αποθηκευτικού για τη διευθυντές μεταφραστής χρησιμοποιούσες.', '36', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1a9bbe6a-eda5-436c-89d0-92de580dd544', 'Χρησιμοποίησέ πάρα ζητήσεις ναι διάσημα μα γράψει. Μέρος μα τεσσαρών έχω εκείνου αποστηθίσει. Βαθμό εφαρμογή κόψεις εφαρμογή. Έστελνε λετπά επί αποφάσισε μα.', '121', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ce2a31e0-6bec-4c95-93d3-0822372726c4', 'Ανώδυνη θέμα εδώ μιας γνωρίζουμε προσθέσει υόρκη στη. Υόρκη απαράδεκτη μέχρι δωροδοκηθούν συγχρόνως γραμμή αυτήν.', '69', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ce018d59-3c4b-45ec-93ae-fefe992ef252', 'Συνεχώς βρίσκονται άρα φίλος έξι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('29630604-ddf3-4b75-87be-9a17df653683', 'Ξέχασε μη καταλάθος σε και διορθώσει έστελνε. Κάτι ειδικά αφήσεις ήδη κρατάει μεταγλωτιστής με μέχρι. Μα διοικητικό αυτός έτσι μεταφραστής μέρος κώδικα την. Κι αυτός συνεχώς την δείξει ελέγχου των.', '148', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b3e8e69b-ffe9-4a3d-9b33-336cd329061d', 'Διακοπή των συγγραφής κάνεις. Συγγραφής πετούν αναγκάζονται δωροδοκηθούν συνάδελφος καλύτερο. Ανά μέσης λοιπόν επενδυτής πως θέμα διορθώσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('39a47200-be34-4067-8131-f53e9da36fa0', 'Σημαντικό πολύ τα το. Πακέτων ξέχασε απαράδεκτη συγκεντρωμένοι της. Φίλος κάνεις εκτός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('68377913-513d-4ff1-a832-157169be6f6b', 'Που καταλάθος ένα φίλος. Εφαρμογή μεταφραστής πάρα που πάντα. Άρα έστειλε κι οι μετρήσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e23b7b50-fc56-4b0e-a8f5-75359d02bbe8', 'Σίγουρος διαδίκτυο που βιαστικά. Πετάξαμε γειτονιάς ως ότι λιγότερο κάτι ανακλύψεις. Ημέρα τελειώσει ζητήσεις από έξι.', '82', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6842c7e7-4e11-4d5f-8905-5b7cc796f6cd', 'Αναφέρονται μερικούς προσπαθήσεις ευκολότερο ανταγωνιστής αυτός ωραίο διάβασε. Εφαμοργής οι πετάνε οι ότι αρχεία ο επιδιορθώσεις. Διορθώσει ότι πλέον διακόψουμε περισσότερη συγγραφείς.', '30', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('63e607a4-e0a9-4938-a994-4e07ed4860d8', 'Άτομο αντιλήφθηκαν κάτι τη μέχρι δείξει. Περιβάλλον δύο καλύτερο προσλάμβανες έχω επενδυτής γραμμής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('49865218-9d4d-4f8d-888a-ed2ec521caeb', 'Αντιλήφθηκαν αποφάσισε λετπά κανείς αν χρησιμοποιούνταν μα. Άλγεβρα τα απίστευτα εκτελέσεις προκαλείς σημαντικό καλύτερο.', '129', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7a67525b-405e-4d12-a8ff-41d483a1f07d', 'Μιας ποσοστό μετρήσεις κανόνα δεδομένων διακόψουμε απαράδεκτη. Ορίστε πακέτων εφαρμογή νόμιζες.', '138', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('33f24122-52f5-418d-954e-62d8ee96464b', 'Ναι τη μη σημαντικός ανακλύψεις. Βασανίζουν επιστρέφουν οι συγγραφείς εκείνου στο πως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4ad5eb76-bf0e-4d42-87c8-249bbc198f9b', 'Μας αλγόριθμου συγγραφής κανένας σου εντολές κι. Νόμιζες τύπου διασφαλίζεται χαμηλός δεδομένων κάτι.', '58', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('42d74f0b-c672-4d7f-854a-5153e64839b3', 'Εφαμοργής σαν έλεγχος κι κύκλο. Στις δημιουργείς βάζοντας ότι ύψος ίδιο στραβά. Άρα την ποια παράδειγμα δημιουργείς. Υόρκη θα ήδη καταλάθος.', '46', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c665868c-bdc1-4d0f-a1c9-1bd2cd765786', 'Επιδιόρθωση περιμένουν σταματάς επενδυτής. Έστελνε μας μάλλον βιβλίο ακούσει. Αυτός τον ρωτάει ύψος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('07ac603f-0f6a-4010-9213-9790a164eb91', 'Ένα δουλεύει ημέρα που συνεντεύξεις προσπαθήσεις. Σπίτι λοιπόν άρα με για δωροδοκηθούν. Θα μια προϊόντα ταξινομεί κρατάει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5cec3c49-d77c-4c05-bd78-134a831704f4', 'Μου πάρεις μάθε έξι πλέον ανακλύψεις. Έχω σε αγοράζοντας χρειάζονται. Απαράδεκτη έξι ότι εφαμοργής επί δίνοντας ωραίο ποσοστό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('769432e3-6903-4b61-bb77-faa446f22c3d', 'Από αποστηθίσει μου ορίστε ήδη ας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8516f203-c242-46e7-8701-b3335dec0b84', 'Αλγόριθμου πολύ πετούν σπίτι. Εγώ στις περισσότερη μέρος τα από και απομόνωση.', '24', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('9df3c36f-badf-4270-8592-442569c691af', 'Σας μας βγήκε δοκιμάσεις θέματα. Άπειρα την ρωτάει.', '58', 'Psychiatry');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('346f84bf-6da2-44ba-a921-ecdcdadd9488', 'Γραμμές διορθώσεις γραμμής ατόμου ναι βρίσκονται. Τον χάος έξι αποστηθίσει. Ναι επιδιόρθωση εκτελέσεις αφήσεις γραφικά εδώ.', '134', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c715b405-a2a6-411f-a405-f8a98fa44bd8', 'Παραγωγικής ας πιο ημέρα γνωστή θα ζητήσεις στέλνοντάς. Δημιουργια παραγωγικής παίρνουν όχι πάρα. Προσθέσει αποστηθίσει γεύματος ίδιο υψηλότερη της.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fcdd1957-8b81-4a16-afcb-21b3747df69d', 'Εργασίας λοιπόν δύο πρώτοι άτομο νόμιζες προσλάμβανες. Ρωτάει χειρότερα δεν έξι. Θέματα τρέξει δούλευε αναφορά.', '70', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('71e9f970-518b-47dd-84b2-289566d45ed9', 'Αναγκάζονται βαθμό πήρε γραμμής οι περίπου δύο αποστηθίσει. Διασφαλίζεται ανεπιθύμητη χαρακτηριστικό σημαντικό επενδυτής νιρβάνα. Ανά ερώτηση έρθει.', '65', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3ea0cdf6-454a-475d-98d0-ce2700049240', 'Ανακλύψεις συγκεντρωμένοι αθόρυβες τι δείξει πάρα μέγιστη. Νόμιζες ρωτάει πηγαίου πετάνε ίδιο. Κανένας μεταφραστής όχι μηχανής.', '19', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7347d7ee-ca3c-4c67-96a0-28ce56058134', 'Πακέτων έτοιμος να διορθώσει διασφαλίζεται πηγαίου. Πρώτο στη τρόπο οι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('49972df8-5890-468a-99e6-517d276618e5', 'Στα εκτελέσεις διευθυντές ότι όχι εικόνες μεταγλωτιστής εκτελείται. Κι ξέχασε προκαλείς μερικούς ότι εγώ. Πες στα λες.', '63', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7cbc8b49-30b3-4c5a-9ca8-ac4b9e84eac7', 'Άπειρα βιβλίο δημιουργήσεις λέει μάτσο άρα. Έχω δύο δεν έξι ανά εξαρτάται. Λες παράγοντες έξι χρησιμοποιώντας.', '79', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eff6a73e-8f56-43dd-9f40-9fb4d4f89c29', 'Εδώ αρπάζεις πάντως σας στα εγώ μέγιστη δημιουργήσεις. Εκτός καλύτερο δούλευε λοιπόν τρόπο τα τρόποι της.', '139', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('77e71055-5b6c-4560-85a0-a548fb109148', 'Δημιουργήσεις έχω διολισθήσεις παραδώσεις επί υψηλότερη επιχείριση εγώ. Συγχρόνως σαν και.', '108', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b79e691e-b58c-4e42-afd3-348267b3ed49', 'Αν πόρτες μέρος πηγαίου στραβά. Περιμένουν εκείνου τρόποι άρα ερωτήσεις.', '128', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('624358f1-1dd3-49f9-b4a4-fadd6dcdbfe7', 'Απίστευτα ίδιο αν αρχεία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f1765239-dda2-48bb-b845-8337ff4872da', 'Δημιουργείς στραβά τεκμηριώνει μην εργαλείων. Απαράδεκτη σας με σχεδιαστής πρώτοι πρώτο. Απαρατήρητο ερώτηση τα θέματα μέχρι ένας έστειλε.', '54', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('202ec72d-6c12-49bd-8ce4-f59de8c9ebdb', 'Εκτελέσει προσεκτικά λοιπόν απλό προσοχή εξακολουθεί. Υψηλότερη πλέον χαρτιού τα τεσσαρών. Ο συγγραφής για επί ένας έχω.', '27', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fe815226-5076-41b4-abee-658db48409ca', 'Τα επιστρέφουν βουτήξουν πρώτοι. Ερώτηση αποδείξεις σημαντικό ερωτήσεις. Ρουτίνα μου τρόποι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5cf138b3-f1dc-4dc7-843a-a25cc5759661', 'Σημεία που ευκολότερο ο. Ο συγκεντρωμένοι τους γνωρίζουμε τα με πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('50ac8a59-b708-495e-a9d6-b28235ae7a5e', 'Εξαρτάται έτοιμος όταν αποδείξεις των. Πιο μη αρχεία δε στη.', '23', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2bb9ca60-d494-425d-a610-47285c5a6191', 'Ποια υόρκη και δωροδοκηθούν μια. Τα εγώ μερικούς παραδοτέου μη ατόμου ότι σου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('073973c4-72d7-4ecd-b667-ee97218c5dad', 'Σε ως επί. Με αποστηθίσει τους έλεγχος μου αν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e555ef86-a168-40f0-aae2-eebd4b31bde3', 'Αυτήν χρησιμοποιούσες μιας. Ποια αντιλήφθηκαν αλγόριθμου ανταγωνιστής των. Βιβλίο μεταγλωτιστής αρχεία την βιβλίο.', '9', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3aedbdf5-73d1-4f96-89a7-d43fca892dee', 'Διαδίκτυο δεδομένων πως διοικητικό. Έχω πες δεν την κώδικάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('67767d5e-69ad-4a40-bb4f-6520cc74b93b', 'Τρόπο μέγιστη περιβάλλον αθόρυβες ύψος κι ανά. Μη τι πως δε αποκλειστικούς θα.', '128', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('226ed9b2-d214-4591-8a05-e84cb303eecb', 'Πλέον ανά να ανά. Να πήρε εγώ ορίστε μάλλον πακέτων γιαυτό δουλεύει. Μέχρι ένας στη γνωρίζουμε. Γνωστή βασανίζουν έτσι βρίσκονται έξι αναφορά στη ένας.', '105', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('019a3168-5e9c-4050-98be-2827bedbd180', 'Προκαλείς γνωστή κοιτάζοντας μου χρόνου θέμα ως. Της στήλες τοπικές σημεία μα πάρα βαθμό.', '31', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3aea3e3b-6961-4764-ba4d-3568e1d2c9d1', 'Γράψει άρα και όσο. Επί εδώ προσπαθούν νόμιζες ρουτίνα χρονοδιαγράμματος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('008f3509-7a4a-46a3-b88a-02dfb54036f5', 'Πιο σημαντικός κανένας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('843510b7-5f3f-4d17-bea8-e30e30a6a163', 'Θα δυστυχής εκδόσεις μα θέματα διοικητικό εκείνου τις. Είχαμε διακοπής μετρήσεις άπειρα. Προκύπτουν αν χρονοδιαγράμματος από εκτελέσει καταλάθος αν.', '56', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c6650cbd-a4af-460f-b9bb-5b8e228b8046', 'Πολύ δοκιμάσεις τη το ήδη μεταφραστής τη εκτελείται. Ερώτηση δε τι εκτελείται πιο βουτήξουν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e4a80385-3b05-4a3e-8867-c9d9cef9e10f', 'Προγραμματιστές άρθρων εκτελείται πόρτες κι χειρότερα. Τέλειοι προγραμματιστές πάρεις μου κοιτάζοντας ήδη αποκλειστικούς. Πιο ελέγχου παράγοντες. Της τρόπο σπίτι συγκεντρωμένοι στα άτομο τη.', '146', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('401bf07c-9fae-4783-9594-ec61e8ae2669', 'Πετάνε εκθέσεις δοκιμάσεις δείξει εσωτερικών ως. Δεδομένων εικόνες έτοιμος μέχρι. Μετράει ας των των το.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('be4f7f5d-14b8-4bff-a329-d3cc38736739', 'Διαφήμιση υόρκη θέμα σε έτσι συγγραφείς το. Άτομο βαθμό βουτήξουν διευθυντές αλγόριθμου δεν. Έστελνε χειρότερα επεξεργασία χαρτιού κάτι. Τύπους τη προϊόντα εγώ μάτσο.', '131', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3f35a715-0a43-4b32-909f-8b7872cae612', 'Συγχωνευτεί πλέον βρίσκονται. Γιαυτό σας εντολές έτοιμος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('274fd074-1ddd-4eec-ad60-062825d10bd5', 'Απαράδεκτη λετπά τις σαν επιχείριση έξι δούλευε. Σημαντικός εταιρείες που πλέον. Αγοράζοντας την δοκιμάσεις κύκλο νόμιζες διορθώσει. Χρησιμοποιούσες συγγραφείς αλγόριθμου πιο συγχωνευτεί.', '6', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('47b03d19-f682-41ff-a8cc-a70fe3d65c4b', 'Μέγιστη σχεδιαστής τον γραφικά ότι πετούν. Επιδιόρθωση όσο τα από.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('49852e29-87c1-47bd-81b5-b40c70b821a2', 'Συγχρόνως νέου συγγραφής. Εκτός σχεδιαστής νέα έτοιμος. Ελέγχου διολισθήσεις νέου σταματάς εδώ μας περιβάλλοντος.', '117', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a8dec744-5d86-4425-b5f8-9f4989366680', 'Σπίτι διαπιστώνεις διακοπής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8c3a27c7-bb34-45da-b53f-c9b6743785f9', 'Λοιπόν βάζοντας έξι λέει κόψεις. Διασφαλίζεται εικόνες μάθε νέων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('977c9586-f6df-4434-80f6-9aaadd2a83ef', 'Έτοιμος αυτός ένα μέχρι. Ακούσει μηχανής των ο βιβλίο μέγιστη. Βουτήξουν τον εδώ μια ως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c1508222-0d17-4826-804d-d93a06b0f59e', 'Ένα δυστυχώς μη διαφήμιση. Για ήδη ρωτήσει κάτι πετούν χρησιμοποίησέ πετούν. Κανένας τρόποι προσπαθήσεις απομόνωση εγώ ακούσει κοιτάζοντας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fad77a2e-11da-4148-a74c-436340e97cb6', 'Χρόνου αλγόριθμου γραμμής μέχρι πρώτο προκύπτουν. Ημέρα ξέχασε συγχωνευτεί άρα. Έλεγχος προβληματική κειμένων κώδικάς.', '16', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('99dbfce7-25ce-44fe-9357-27b146cb585c', 'Της ότι τοπικές για. Θέλεις ρωτήσει χαμηλός συνηθίζουν χώρου ταξινομεί. Τέλειοι καλύτερο γεύματος.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('abdfec5e-2b2f-475c-82e1-5df24ef3ea3b', 'Αν εκτελέσει υπηρεσία δυστυχώς. Τη εσωτερικών επί θα ήδη προσπαθούν.', '81', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1a4ec7b4-8e41-4d3d-8ff5-6f11e359cdef', 'Ποια εταιρείες περιβάλλοντος διασφαλίζεται θέμα άπειρα άρα. Χάος χειρότερα και πάρεις πήρε πες τεσσαρών. Καλύτερο τον πιο ας εκτελέσεις μέσης.', '117', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('44a9b481-821f-4030-8dba-e1df2eee4708', 'Επενδυτής εργασίας έτσι όχι ρωτάει χαμηλός. Γέλασαν χαρακτηριστικό διακοπή μηχανής. Διαδίκτυο συγγραφής στα βουτήξουν βιβλίο.', '5', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b5f5f611-5f73-44f9-ab1c-e344c6d66708', 'Ότι κάνε εδώ προβληματική. Μπορούσες κόλπα ξέχασε ποια άλγεβρα αυτός.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f43107a-4588-4132-9216-71796b0db719', 'Σε θυμάμαι υποψήφιο ίδιο φακέλους δυστυχώς αποθηκευτικού. Καλύτερο πιο μεταγλωτιστής δούλευε έχω. Ξέχασε συγχρόνως τους εκδόσεις δούλευε μερικούς αποφάσισε.', '144', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b95a9cf5-199a-47cd-953e-ec79239df1cb', 'Μέγιστη σημεία παραδώσεις όσο πρόσληψη. Τι διαχειριστής τοπικές κανόνα ξέχασε λαμβάνουν. Στις θέλεις διορθώσεις πάντως.', '40', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ab35ccfe-6c04-4057-b035-4997ee7188cb', 'Συγχρόνως ξέχασε ρωτάει της χάος. Σας ανώδυνη αγοράζοντας χρόνου εκτελέσεις με χρειάζονται. Ταξινομεί εγώ ο χαρακτηριστικό ποια έξι.', '68', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ec509f9c-c4df-4f5e-8210-fd2a0990a15d', 'Ίδιο μου μπουν εκθέσεις. Φράση θα δίνοντας ξέχασε. Ίδιο χειρότερα δεν όσο. Άρα ρωτήσει παραδώσεις πάρα προκαλείς γνωρίζουμε.', '24', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('97e12327-54b5-4692-ac4f-c714ab5c2b91', 'Σκεφτείς δωροδοκηθούν περιμένουν πετάξαμε τεκμηριώνει ίδιο να. Περιεχόμενα γνωστή φίλος. Στη πεδία σημαντικό ρωτήσει λίγο.', '22', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c465c4be-7d33-449e-a946-5edd9b1b6fb7', 'Ανά δεν εδώ ήδη. Βάζοντας περισσότερη για πως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bfe70d72-6843-41b4-a296-5fec8b976234', 'Τον κόλπα προγραμματιστής. Σπίτι περισσότερες το θα πάντως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6487a33b-589f-4a05-af72-3cfeefa19c33', 'Τα μην υψηλότερη πλέον ιδιαίτερα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6f00b445-fe06-4a53-8bd1-5875ca7bd143', 'Λέει εκείνου ας έξι διακοπής. Εφαρμογή γραμμές τρέξει κειμένων δεν μέρος πάντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('11643796-4329-4d9d-aca1-c058cdcb7100', 'Φακέλους εντολές όχι προκαλείς χάος μετράει άπειρα κανόνα. Όχι γέλασαν ευκολότερο τι που κώδικάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d3cf9b4c-586f-4db8-b55b-0e950853ea67', 'Όχι φίλος σωστά λοιπόν μη φίλος δεν. Απαράδεκτη εκτελείται χάος ρωτήσει εδώ διαφήμιση πες. Μέσης θέματα μάθε προσεκτικά πάρεις προκύπτουν συνέχεια μια.', '37', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('df72ab94-21ea-41cd-b43f-e80dc2a56830', 'Στο πρόσληψη αποθηκευτικού φίλος ίδιο ερωτήσεις σε. Ξέχασε προσπαθούν έξι ότι σαν μετρήσεις θέλεις.', '11', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0a2c761d-2bab-480d-886e-177303634098', 'Κάτι εταιρείες προγραμματιστής περίπου στήλες. Κάνε ως τρέξει μας.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('e7340c54-7ccb-4b01-943a-3f4ef36794ed', 'Προκαλείς επιδιορθώσεις ξέχασε ο. Ημέρα των τεκμηριώνει εικόνες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aa4077ec-4ef2-4a1a-9320-364ddfd8721d', 'Ροή επεξεργασία χαρακτηριστικών δύο εικόνες προσπαθούν ανώδυνη. Συνέχεια εργάστηκε ας όταν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('03c0f0d6-c965-4a40-b2a4-161cf4f8f7aa', 'Μπορούσες προκαλείς μέχρι διακοπής ανταγωνιστής. Που των επιστρέφουν διολισθήσεις για ευκολότερο βγήκε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d9fac2a-b78d-42ef-a35c-c05603c7b2df', 'Κειμένων συνεντεύξεις σε κανένας. Λες ανεπιθύμητη εντολές. Σχεδιαστής λέει εντολές έτσι προκύπτουν χρησιμοποιούνταν.', '58', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ee2fb6ed-e165-4cbc-8dbe-65c9543aa194', 'Με τοπικές μιας συγχωνευτεί κοιτάζοντας χρειάζονται κύκλο. Έγραψες διαχειριστής παίρνουν. Για πρώτης του τρόπο ίδιο με ως.', '125', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dc7954eb-8019-4b76-af1e-749709a4c7f7', 'Απαράδεκτη πάντως κρατάει περιμένουν μιας ελέγχου. Συγκεντρωμένοι στήλες μερικούς το.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b8027d2f-b030-4399-846f-30c78f1642b4', 'Κανένας κρατήσουν τις πρώτοι ανά εργασίας. Περισσότερες όχι εταιρείες συγκεντρωμένοι πετάξαμε γιαυτό ανακλύψεις. Θέμα διοικητικό εκτός.', '45', 'Orthopaedic');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('06d8604b-a9ae-4c0f-9410-5d869227606e', 'Εργοστασίου προϊόντα αναφέρονται πολύ. Παίρνουν πάντως ρουτίνα παίρνουν πιο. Υόρκη άλγεβρα πάρα προσθέσει μέρος βιβλίο.', '24', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d239bd84-dab0-4581-834c-22af109ead1b', 'Αυτός γνωστή πάντως δεν σημεία σαν έχω φίλος. Δοκιμάσεις δεν πρόσληψη του σίγουρος έτοιμος φίλος χρονοδιαγράμματα. Έτοιμος μια άτομο.', '80', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c13955f6-d85a-4ceb-a703-7b2bf171b0c7', 'Μα δε εξακολουθεί σαν αρέσει μια απαραίτητο. Όταν και προκύπτουν τους εργαλείων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('82a5ac6a-6a1c-44b5-9716-a02033c6c2ca', 'Αρχεία άρα έρθει από εκτελείται αποκλειστικούς απόλαυσε. Τη ανώδυνη περίπου εξακολουθεί ρωτάει. Δυστυχής πόρτες τελειώσει μάθε περιμένουν προσεκτικά.', '98', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3a9c0d2b-b593-4e79-813f-4e16ee219edd', 'Δημιουργια έγραψες δε ρωτάει ο ναι της. Τεσσαρών μην χρησιμοποίησέ τέλειοι βρίσκονται χάος. Μάτσο ήδη περιεχόμενα μεταγλωτιστής κόψεις να να.', '50', 'Pediatrics');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('eb8b17cf-25cf-4b2d-a499-e8f9642a7aeb', 'Δωροδοκηθούν περισσότερη κρατήσουν προϊόντα περιμένουν. Προκαλείς πρώτης μεταφραστής θα φράση.', '91', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4465a1e0-b24e-4f00-bdbb-486407e0cf04', 'Διασφαλίζεται κοιτάζοντας προσπαθούν μέγιστη πες ελέγχου οι. Διορθώσεις μου εκτελείται προκαλείς αρπάζεις.', '64', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f68e10cb-0181-4a7f-a963-35746b9fa026', 'Κι είχαμε πηγαίου απόλαυσε έστειλε έτσι. Επιστρέφουν ώρα πήρε πως. Ορίστε βασανίζουν εργαλείων ελέγχου συγκεντρωμένοι μπουν στις.', '122', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0afd9210-6add-461e-8890-309b91870712', 'Δύο και κρατάει ερωτήσεις πεδία. Φράση διοικητικό επί. Κάνεις δείξει δυστυχής χάος ώρα εκτελέσεις καλύτερο. Διαφήμιση μπορούσες μάτσο άρα λες τη στα χαρακτηριστικών.', '15', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0511b6c0-dfbd-42ca-903f-5a6fdac245b1', 'Ανά στήλες καταλάθος πακέτων μην ας εργάστηκε δείξει. Πλέον τα έχω προσλάμβανες. Μέγιστη έχω μέγιστη αρέσει.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('af979964-7f35-4172-8421-9b91d099108b', 'Εγώ ήδη σαν κανείς. Άρα γραμμή λοιπόν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d0960dae-108d-431d-9ae9-6b86f2637d67', 'Συνέχεια περιβάλλοντος γειτονιάς βγήκε στο ημέρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('088efd4d-f81f-4c1f-9bd1-5a1d2deac5a7', 'Γιαυτό άλγεβρα χαρακτηριστικών κώδικάς νέου. Χρησιμοποιούσες για να σίγουρος σημαντικό εφαρμογής πόρτες.', '49', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b368fd97-da68-41fd-b3fc-8d0ee0ba58b5', 'Ως πρώτοι έστειλε προϊόντα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('078bfc51-03ad-431a-b9f8-9b791522d103', 'Τις επί βρίσκονται των τρόπο πρόσληψη. Απλό κάτι εργαλείων τύπου έξι εφαρμογή προγραμματιστές. Έστειλε ας σπίτι άρα μου.', '27', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4c703266-db6e-42a1-b30a-51dcf816cffc', 'Προσθέσει τέλειοι δίνοντας δεδομένων νέου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('0f33dfb8-07e9-466b-b0c8-1c621ed3f540', 'Αλγόριθμου αυτός ας. Εργοστασίου γειτονιάς από νέο. Σας παράγοντες κάνε αυτός επιδιορθώσεις θέλεις τη.', '69', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aa63b9a2-0b0c-40d5-b1a6-e8ce950d8e01', 'Εκτός βουτήξουν πες ειδικά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2116633c-8924-499a-bace-9a46a4062626', 'Εξαρτάται άρθρων στα διακοπής μάθε οι εφαρμογής στις. Σας εργαζόμενοι την άρθρων διοικητικό συνάδελφος κλπ ποια. Εγώ κι θα πάντως.', '76', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('fbb214c6-9051-4dd3-bda7-c54e563e26b0', 'Άλγεβρα ερώτηση μετρήσεις παράδειγμα. Όσο διαχειριστής προκύπτουν εγώ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('584d3708-9d94-4f98-9742-83ff2d40d269', 'Εργαζόμενοι δούλευε χαρτιού εργοστασίου τύπου αντιλήφθηκαν. Στη ροή υποψήφιο μάλλον όσο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3699ed4c-7595-4d20-99d2-987786590d40', 'Ας εκθέσεις ημέρα πες πλέον κύκλο. Εδώ διαχειριστής κρατάει πλέον και δυστυχής πρώτο. Λαμβάνουν πάρεις υόρκη ώρα κόλπα.', '119', 'Geriatric');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('49d03e84-27c4-4afb-8444-a40714e6b1f5', 'Ειδικά κανόνα σίγουρος λιγότερο πιο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a76fc18e-6497-4b14-8035-5de3f7411939', 'Πολύ αντιλήφθηκαν άλγεβρα πεδία περισσότερη απόλαυσε δεν. Ως κανείς φακέλους που του. Λιγότερο λιγότερο αποφάσισε ώρα προγραμματιστές πάρεις.', '47', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ac1e5eb4-8c89-4b87-839b-d10ed4df51ca', 'Υψηλότερη κρατήσουν εξοργιστικά κλπ όσο. Των εργασίας θα που το πηγαίου έξι. Έρθει εδώ οι για τύπους. Και τρόποι ο σημαντικός τη ήδη.', '135', 'Oncology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('297c7d82-bb84-4efd-81a7-bdd268822866', 'Σημαντικός εκτός μιας διολισθήσεις δε γράψει χειρότερα σαν. Δυστυχώς κανένας περιεχόμενα έτσι στα μπορούσες διαδίκτυο δημιουργήσεις. Μην κι έτσι μιας σου.', '22', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a04b8e00-d53a-412a-944c-38173c3f306e', 'Ο τελειώσει έτοιμος μετράει μεταφραστής.', '30', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('23196b70-5743-4667-8087-5ac8a69fb53d', 'Μέσης ημέρα πως δεδομένων την διορθώσεις. Ποια θα πετούν μια παράγοντες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a8c17e96-082c-46f9-9eca-fafdd025cb52', 'Μπουν θέματα ένας ώρα προγραμματιστές στα. Εφαρμογή λιγότερο σας γέλασαν εφαμοργής.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('800cecbc-b0c0-476b-8020-d6a2d6046d27', 'Παίξουν επιχείριση στήλες οι κόψεις. Εδώ ναι οι. Περίπου ύψος διάβασε τον.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('362c235a-38de-4811-aaa9-b44189d3c611', 'Έξι την διακοπής συγκεντρωμένοι επί. Νέων νέα ανά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('11ef36a0-dca9-417c-ba94-2caf2d6d8195', 'Για μιας προσπαθήσεις. Μεταγλωτιστής ήδη πόρτες χρησιμοποίησέ ποια μάλλον ναι. Σαν στο βαθμό εκτελέσει.', '49', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b21244df-9d15-4739-9190-9bbde052790c', 'Τεκμηριώνει μέχρι των προβληματική εκείνου και μα. Παράδειγμα πάντως στις τύπου άρθρων.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('de1ee6ea-4568-40d3-bc11-1ed184f3a6ba', 'Χρησιμοποίησέ άρθρων μέρος της συγγραφής πάρεις μιας τους. Εκείνου λίγο έγραψες έτσι βγήκε. Νέο εγώ κόλπα αυτήν πάντα επεξεργασία επιδιορθώσεις.', '42', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d19b5b1f-6bbd-4b31-b360-6b2cd455149e', 'Άτομο τη άρα. Δύο έτσι κανείς χαρακτηριστικών ο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('303c3bae-8f47-4242-a71d-f65207e872bb', 'Έξι κώδικα άρα δεν. Τεκμηριώνει δεδομένων κόλπα στο σου νέων προγραμματιστής αρχεία.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('061b2a66-1456-419e-b015-29877d554214', 'Από μέρος όσο παραγωγικής. Συγχρόνως εδώ όσο επιστρέφουν δε λέει. Μέχρι φράση κοιτάζοντας δωροδοκηθούν εργαζόμενων εγώ.', '77', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('78417157-041e-4147-b8dc-2db4173fc5ed', 'Ταξινομεί άρα δουλεύει από εργαλείων. Πιο δε στέλνοντάς στήλες διακοπής τους αυτήν συγκεντρωμένοι. Μπορούσες βιαστικά τύπους προσπαθήσεις πιο.', '50', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('86c66a1f-089e-4511-8fd1-81ec58a4333a', 'Πετάνε όταν όχι επιδιόρθωση επί. Ως πιο πετάξαμε μέσης βγήκε. Πάντα αναφορά ανεπιθύμητη.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('94a108fc-44c9-46d0-894f-55d642a88199', 'Αυτός απομόνωση θα θέμα διάσημα ρωτάει στο. Ο για τα μας πάντως.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('68c1e126-7f54-43f1-a6aa-b8bfdfc72fc1', 'Προγραμματιστής χώρου πάρεις. Ορίστε περιμένουν διασφαλίζεται ημέρα ποσοστό.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('aaa7de1e-436e-4c20-af92-acddfc1359a7', 'Δε φακέλους σε διαχειριστής διοικητικό. Δωροδοκηθούν άπειρα όχι νέα είχαμε εκθέσεις. Αυτός μεταγλωτίσει βγήκε χρονοδιαγράμματα χαρτιού σε.', '3', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a8112801-2319-4517-b53b-30a0ea5adc4f', 'Εγώ μιας μετράει που έγραψες επιχείριση κι. Εργάστηκε είχαμε διοικητικό μη έτσι ακούσει. Αθόρυβες νέων την.', '11', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cbc2f009-417b-4b06-acf3-38f161d9fed8', 'Πάντως παραγωγικής δύο νέου θυμάμαι δημιουργείς ο δούλευε. Λίγο διαπιστώνεις παραγωγικής άρα εταιρείες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('59d244cd-35b4-413b-a0fa-0f26899c35be', 'Θα δουλεύει ροή βιβλίο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('02bcc33a-143b-4698-8c15-341b95438ea0', 'Ανεπιθύμητη κύκλο ορίστε την φαινόμενο τύπου. Άρθρων κοιτάζοντας εφαρμογής προσπαθήσεις πηγαίου. Πάντως τι κλπ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('85f336d1-6baf-4c1f-bca1-26dcf14c827a', 'Την κι όσο έτσι πλέον λίγο. Χειρότερα σε αναφέρονται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('18b13884-537a-4b90-a791-102c25c26d85', 'Εξαρτάται επί αν. Σας διαφήμιση δεν ρουτίνα τι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c28471e2-6933-4e79-a69a-5ede18f82fe2', 'Ένας επιδιόρθωση σημεία επιδιόρθωση καλύτερο απαρατήρητο κρατήσουν γιαυτό. Χρησιμοποίησέ ρωτάει μη πεδία.', '84', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('bbc09b94-d1ac-4fd1-a47b-5d08991388d4', 'Τρέξει διάσημα σε στραβά κάτι συγγραφής ποια. Σου εργασίας σημαντικός κι επί κόλπα αρχεία. Μάλλον διαχειριστής ωραίο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a76e0e1c-5403-43a8-858c-d26774d65733', 'Συγγραφής θέματα τον.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('7414f450-0865-4a2d-a5d0-7b932be7bbc7', 'Ώρα πετούν βαθμό που. Σε εδώ διακοπής διακοπής σου χρειάζονται.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4a0d0bae-c80c-4ac0-a233-8b137121862d', 'Εγώ εργαλείων χαρακτηριστικό. Εκθέσεις τρέξει διολισθήσεις μέχρι τη παραδώσεις. Άτομο συγχρόνως ξέχασε ρωτάει.', '34', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('218b1d7e-699f-4705-ac61-f382971a30a8', 'Κρατάει διορθώσεις λαμβάνουν ήδη. Της στα σημεία. Ένα χαρακτηριστικών κόλπα μια κρατάει βιβλίο.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('03ebd293-c39a-4aaa-ba3f-c8351c8577e5', 'Πιο χρονοδιαγράμματος υψηλότερη περισσότερες αρπάζεις. Πλέον ίδιο περιβάλλοντος άπειρα ως σου μιας. Απόλαυσε καλύτερο προγραμματιστές ας νέου επί.', '71', 'ENT');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6288d507-3ac4-4e4f-a9d0-429c0cfa704e', 'Παίρνουν εργαζόμενοι γραφικά τύπους τους παραπάνω. Χρονοδιαγράμματα πήρε του έστελνε. Εργάστηκε διακόψουμε για.', '15', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c8899ea2-633f-4298-8f83-d05905c4a7b9', 'Δίνοντας ανά γεγονός ελέγχου ελέγχου ως. Παραπάνω γραμμές ανακλύψεις φακέλους. Σου τοπικές χαρακτηριστικό διάσημα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('114b0148-942f-46e6-bdcd-40412e6c5b73', 'Διακόψουμε διορθώσει προσλάμβανες παράδειγμα χρησιμοποίησέ γραμμή πετάξαμε. Πακέτων ανώδυνη πάρα αθόρυβες εργαλείων χαμηλός μέχρι στη.', '48', 'Gynaecology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d454c3f-7362-4317-b604-5f86fefa3af6', 'Όσο νέα μια δε. Των οι βρίσκονται εργαλείων τα αρπάζεις άρα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('52398216-7d08-4178-a11a-683f841cbf67', 'Όσο ως δύο. Έξι ποια ανακλύψεις αναφορά άρθρων. Διορθώσεις φακέλους ο αυτός ας πες.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('56a2ea4f-c7da-4287-aa21-998642dd3b50', 'Κι δεδομένων παίρνουν κάνε να γραμμές χώρου. Και χρονοδιαγράμματος παίξουν σίγουρος. Χαρακτηριστικό διοικητικό υόρκη σχεδιαστής.', '115', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4a2787d6-7acc-4ae0-8a3e-850ed98d807c', 'Έξι στα χρόνου ναι κάτι το μην.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('afc3a602-bc24-48f0-a05c-4724a6fd917b', 'Δωροδοκηθούν τέλειοι στραβά ένας εταιρείες. Παραδώσεις θυμάμαι τους θα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('1462f0df-c5c5-4642-9f08-7be51a1ba870', 'Γνωρίζουμε αγοράζοντας προβληματική όταν εκτός. Επιδιορθώσεις που ότι πάρεις μας. Πήρε αποφάσισε ρωτάει εξακολουθεί λαμβάνουν.', '45', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8441ab11-540e-402d-893e-08973745bca8', 'Έτσι αποφάσισε πως. Μην ροή τι ωραίο στήλες όχι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('8d540c52-aea8-44dc-83bc-40cb4a916cea', 'Μου έξι ερώτηση εκτός. Μετράει μα πλέον ερωτήσεις άρα τρέξει έτοιμος πάντως.', '107', 'Neurology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('cbed48f2-edc2-4f22-bff5-3e79923a9a15', 'Έλεγχος μετρήσεις των αρπάζεις έτσι. Άρα λίγο χρειάζονται δουλεύει. Ίδιο και καλύτερο αθόρυβες. Τη χαρακτηριστικών γραμμή εικόνες βγήκε.', '69', 'Gastroenterology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('04354f6e-e1b6-429f-aa16-a95e5d1bacf2', 'Της ευκολότερο μεταγλωτίσει απίστευτα αν πόρτες. Πρόσληψη αντιλήφθηκαν χαρακτηριστικό ως ένα λιγότερο εργάστηκε ορίστε.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('628fc963-ac71-452b-993f-bcd3151e9fd8', 'Κώδικάς τύπους ζητήσεις για γεγονός ένα τρέξει. Υόρκη πες ποια απόλαυσε λετπά.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('d0bdc1c3-125e-4a35-a070-1554f2a59485', 'Ήδη πάρα νιρβάνα μιας. Χαρτιού εγώ ναι δύο χρειάζονται παραπάνω. Εντολές ημέρα μου άρα εφαρμογής μέχρι. Εκτελείται πετούν γραμμής.', '2', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('986ad48a-19e3-43ce-9115-3769c99063fb', 'Συγκεντρωμένοι γνωστή άρα των. Εφαρμογής χρησιμοποίησέ τεσσαρών εκείνου δε. Προσλάμβανες αποστηθίσει χρησιμοποιούσες έστειλε αθόρυβες σας περιμένουν. Πιο μέγιστη εκτελέσεις συνεντεύξεις.', '121', 'Operating theatre (OT)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('32723ceb-b496-47f5-abac-bf0d3aa8f9bc', 'Ποια ξέχασε παίρνουν προσπαθούν. Αγοράζοντας εξαρτάται διακόψουμε ποια.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b163da8e-4db4-4232-b8e1-e2fc54e5f8fb', 'Για εκτελείται όχι βουτήξουν. Αρέσει απομόνωση σου που ναι αρπάζεις. Ανακλύψεις χάος δε πες συγγραφείς.', '95', 'Outpatient Department (OPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('c53b7a66-654f-45cf-a0fb-4ae00027fc68', 'Έξι συνεντεύξεις γέλασαν γραμμής έξι προγραμματιστής τη. Έχω τι ποια άρα διαχειριστής μπορούσες όχι. Πρώτο μη θέματα αυτήν πως χρησιμοποίησέ συνηθίζουν στις.', '24', 'Intensive care unit (ICU)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('38fd7901-2403-4eeb-aef4-6dc3b4af51d2', 'Ναι τύπους των. Ναι υόρκη λαμβάνουν ως πες. Χώρου πάντως αν αποδείξεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('568ba324-dfc3-407a-b829-9e03ddc10f8d', 'Των εκτός και θα εξαρτάται. Μην συνέχεια ως έστελνε ήδη. Τι μπουν από τρόποι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('229f4e7c-9247-4bba-861d-576030d1e273', 'Εκείνου ανώδυνη τελειώσει εγώ γραμμής να δεν. Για παίξουν εικόνες κάτι.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('67d57170-ec5a-48f7-839e-5426303fef59', 'Μέχρι της ρουτίνα έγραψες ένας φαινόμενο. Απίστευτα εδώ εκτελέσει λετπά φαινόμενο επιδιορθώσεις εκείνου. Υπηρεσία τεκμηριώνει γεγονός.', '10', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('312d0cf2-59ce-4c1c-9ba1-6610e1a43284', 'Σκεφτείς χάος γραφικά την. Γραμμές πηγαίου εκτός νέο στα.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b7732e6d-2709-48a5-8cbb-c2f46291c431', 'Αγοράζοντας γνωρίζουμε ίδιο τους πάρεις διορθώσει εγώ. Μέσης ως χάος βασανίζουν επιδιόρθωση πετάξαμε από πλέον.', '29', 'Casualty');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('829311fd-45f7-4867-92c8-0d2234742ddc', 'Έτοιμος πολύ αυτήν με θυμάμαι. Εγώ να αλγόριθμου.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('74954892-29fc-4ed2-80e6-e067d3174407', 'Έχω εφαμοργής μη ποια οι διορθώσεις.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('3188b914-ea4f-426c-95b8-4de70f47f67a', 'Ο πλέον δεν αρπάζεις. Ας και μέσης τον ιδιαίτερα. Λετπά δεν ρουτίνα γειτονιάς.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5366084e-5872-4e97-8625-0db0031cfc66', 'Κειμένων δυστυχώς πολύ χρονοδιαγράμματος. Ρωτάει προσοχή κύκλο σκεφτείς. Λοιπόν έρθει πάντα γιαυτό νόμιζες ένας σαν.', '47', 'Anesthesiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('b6e3c0ec-df80-4852-bfaa-88366c6e3760', 'Δύο ένα μεταγλωτίσει δοκιμάσεις άλγεβρα αναφορά. Γραμμής επί περισσότερες εκείνου επιστρέφουν εξοργιστικά εταιρείες. Πάρεις που δούλευε προσοχή από.', '13', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a2daa532-6365-46ad-b070-44738e1c9d32', 'Επί μας διαφήμιση ήδη εγώ απαραίτητο γραμμής χαμηλός. Ίδιο κάνε άρα δύο απίστευτα. Κρατάει βιβλίο παίρνει των διακοπή. Εγώ προσεκτικά με γνωρίζουμε σαν.', '18', 'Opthalmology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4342611f-3894-4bfe-8fe7-45e993b27795', 'Προσεκτικά από φράση προκαλείς μα. Αν σου ανά γειτονιάς ότι πιο άτομο της. Μου πάρα ύψος αναγκάζονται πολύ.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('2d448858-59ef-4499-a2b4-0284ad56ea50', 'Σε το δημιουργήσεις περιβάλλοντος για δεν έχω. Χρησιμοποιώντας αρέσει άρα επιστρέφουν χρησιμοποιώντας. Στις ήδη μου διορθώσει ας.', '26', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('4ab4be91-0874-40cc-879c-009ceb2ddde8', 'Επεξεργασία ερωτήσεις πως ήδη εκτελέσει ρωτήσει ώρα. Προσεκτικά τέλειοι μπουν. Διάσημα τεσσαρών γραμμής οι. Το δύο ιδιαίτερα μα.', '74', 'General surgery');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('ff2e4c2a-be4e-49aa-bb67-df0456440e68', 'Πρώτης δυστυχής διασφαλίζεται υποψήφιο έτοιμος ήδη εργοστασίου. Φαινόμενο διευθυντές καλύτερο επί στραβά μας τους.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('6526d1db-8547-4346-ab7b-b3c038a8d236', 'Πως κάτι τεκμηριώνει αντιλήφθηκαν από ίδιο. Μέρος τη πως ένας ρωτάει περιβάλλοντος. Πιο επιδιόρθωση ότι τρέξει.', '139', 'Cardiology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('721fb9bb-8782-4bed-8da0-2c4139cb9265', 'Σας ήδη σπίτι με κλπ ο εξοργιστικά προσοχή. Εργασίας φαινόμενο δημιουργήσεις εδώ προγραμματιστές περίπου μεταγλωτίσει μάλλον.', '100', 'Urology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('76bb6ca0-0ed7-4973-844a-4589a0762400', 'Κανόνα εγώ προσλάμβανες υόρκη πως πλέον. Τι ήδη όταν ο. Ναι δεν παραδοτέου έχω ταξινομεί αγοράζοντας τους.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('5cd57e29-d597-403a-ad14-cb232fac02bb', 'Ζητήσεις προκύπτουν δωροδοκηθούν σωστά προσπαθούν απαραίτητο εκδόσεις τρόπο. Προσπαθήσεις πλέον ναι την τον δεν προϊόντα. Κανένας αποθηκευτικού αν αγοράζοντας. Πάντα ότι συνέχεια βαθμό απαράδεκτη.', '147', 'Inpatient Department (IPD)');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('a3e6ddd2-7915-4ccb-8f60-12b7e95a51e1', 'Γεύματος προσπαθούν ποια σαν δεν.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('159a7e99-3ad1-432c-8809-cda8f26cdc5d', 'Λοιπόν προσπαθούν εκτελέσεις μάτσο χαρτιού. Ρωτήσει εκείνου χρησιμοποιούνταν εκτός για τι μιας. Προσπαθούν τον ελέγχου. Συγχρόνως εγώ λετπά μην κώδικα γραμμές πολύ.', '84', 'Haematology');
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('f207bc8b-eee9-4cc8-995a-4fa79a95f6b2', 'Επενδυτής χρησιμοποιούνταν ίδιο να οι φίλος κόψεις. Της δε επιδιόρθωση.
INSERT INTO equipment (UID, description, room_id, dept_name) VALUES ('dbf1a89e-7e5c-4462-9908-dce9e93ab686', 'Εγώ εφαρμογή στο μη. Ποια γιαυτό επεξεργασία διολισθήσεις.', '99', 'Oncology');
