INSERT INTO media (path, description) VALUES ('/media/images/image_ab.png', 'Επί νέων αποδείξεις πάντα ανεπιθύμητη κάνεις της.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('1', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_error.jpg', 'Βγήκε πάντως περίπου στη. Θα ένας πιο σημαντικό δυστυχής γεύματος άπειρα. Ώρα τη πηγαίου την.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('2', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_dicta.jpg', 'Ερωτήσεις διαχειριστής εκτελέσει έστειλε πήρε. Από τον εδώ δε κοιτάζοντας άρθρων.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('3', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_eius.jpeg', 'Νόμιζες εξαρτάται έχω πλέον ίδιο γνωρίζουμε. Προσεκτικά σε αθόρυβες δεδομένων. Ώρα σκεφτείς αντιλήφθηκαν εκτελέσεις δύο.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('4', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_officiis.jpg', 'Θέματα ερωτήσεις αποθηκευτικού τη επί αποστηθίσει. Απλό εγώ γνωρίζουμε. Ορίστε αποκλειστικούς αθόρυβες χώρου δούλευε μερικούς.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('5', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_repellendus.jpeg', 'Θυμάμαι πιο πάρεις. Με προγραμματιστές προσπαθήσεις διαδίκτυο εδώ ροή. Πάντως χρόνου σημεία διοικητικό στα παραπάνω.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('6', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_deleniti.jpeg', 'Αποστηθίσει από ρωτήσει δύο κρατάει επιστρέφουν δυστυχής. Βουτήξουν αναγκάζονται ένα διολισθήσεις βγήκε τρόποι γειτονιάς. Μέχρι την δίνοντας γνωστή.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('7', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_quisquam.jpg', 'Διαφήμιση όσο προσπαθούν δύο πακέτων. Φράση έστελνε μη εδώ πάντα επιχείριση. Με εργασίας ιδιαίτερα μη εφαρμογής παραγωγικής σας.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('8', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_est.jpg', 'Σημεία υποψήφιο επί διακοπή. Στα υποψήφιο την χειρότερα.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('9', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_ea.png', 'Πάντα λαμβάνουν απαράδεκτη δεδομένων εργασίας εγώ. Θα λιγότερο αυτήν αντιλήφθηκαν.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('10', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_modi.png', 'Φαινόμενο πολύ στα παράγοντες χρησιμοποίησέ διαφήμιση. Ανά μέρος μπορούσες κι εργοστασίου.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('11', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_eius.jpeg', 'Μου αρπάζεις υόρκη πόρτες ας. Ιδιαίτερα ορίστε στη. Κι μπουν μέχρι ίδιο πρώτης. Τον τρόπο πλέον παίρνει συγχρόνως.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('12', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_vero.jpeg', 'Νέο λίγο διαχειριστής μάτσο προσπαθήσεις ώρα. Μη ερωτήσεις ταξινομεί περισσότερη κλπ περισσότερη μέρος.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('13', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_saepe.png', 'Πρώτο ένας που μεταγλωτιστής. Υψηλότερη χρονοδιαγράμματα γειτονιάς στη της από κάτι. Ρουτίνα έτοιμος συγχωνευτεί ότι συγκεντρωμένοι διαχειριστής έγραψες. Γειτονιάς διορθώσει και διακοπή.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('14', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_iusto.jpg', 'Ανταγωνιστής μιας γιαυτό αυτήν ας. Σίγουρος χάος ευκολότερο τον τρόπο άτομο.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('15', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_id.jpeg', 'Ερώτηση αποθηκευτικού του δημιουργείς δυστυχώς. Υψηλότερη ταξινομεί πεδία είχαμε φράση σπίτι. Τα να περισσότερη μέγιστη περισσότερη προκύπτουν. Τεκμηριώνει μια κλπ και μέρος έτοιμος.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('16', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_odio.png', 'Έξι ανώδυνη μπουν σε.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('17', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_quos.png', 'Βιβλίο εγώ σχεδιαστής τους σας ωραίο φίλος. Σημαντικός τι ίδιο πετούν χαρτιού στη.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('18', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_hic.jpg', 'Ερωτήσεις χάος μεταφραστής χρησιμοποιούνταν αντιλήφθηκαν. Επιδιόρθωση διαδίκτυο μα τι συνέχεια. Εξοργιστικά αυτήν μια υψηλότερη δοκιμάσεις χαρτιού.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('19', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_harum.jpg', 'Στη επιδιόρθωση εταιρείες όσο του συγκεντρωμένοι. Κλπ ρωτάει σημαντικό προσοχή προσθέσει βασανίζουν μια. Τον έστειλε με δημιουργήσεις λες προκύπτουν.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('20', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_vel.jpeg', 'Προκαλείς βάζοντας κάτι δε θα πολύ όταν. Επί θα σημεία. Κανένας κρατήσουν παραπάνω σου προσπαθήσεις τρόποι.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('21', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_aut.jpeg', 'Για δε έτοιμος αθόρυβες σχεδιαστής εκτελέσει. Εφαμοργής τα αντιλήφθηκαν πάρεις. Πήρε μεταγλωτιστής οι δημιουργια θέλεις.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('22', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_ad.jpeg', 'Κόψεις βιβλίο ποσοστό προσθέσει κειμένων επί. Τεκμηριώνει μας και. Αποδείξεις σαν να νέα πάντα πόρτες λετπά.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('23', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_sit.jpg', 'Τύπους δεδομένων κρατήσουν στο εδώ ποια. Διάβασε για δύο ανά επεξεργασία προσπαθούν.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('24', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_dolor.jpeg', 'Τη εδώ ωραίο χειρότερα. Σημαντικό κώδικάς εκτελέσει υόρκη λετπά αθόρυβες που αποστηθίσει. Επί κρατήσουν ως άπειρα πρώτο.
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('25', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_ullam.png', 'Μη στις φίλος τέλειοι προγραμματιστής βουτήξουν εσωτερικών αλγόριθμου. Διασφαλίζεται πρώτης ο έχω ήδη σε χρόνου εγώ. Παράγοντες ημέρα απαραίτητο καλύτερο κώδικάς περιβάλλον ατόμου την.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('26', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_commodi.jpg', 'Μιας ένας ως πολύ δίνοντας τον αναγκάζονται προσπαθούν. Παίξουν δωροδοκηθούν όσο.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('27', 'doctor_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_aliquam.jpg', 'Μεταγλωτίσει δεδομένων νιρβάνα δυστυχής ερωτήσεις ποσοστό. Των μερικούς γραμμές νέων. Ανεπιθύμητη ανά προσοχή εκτελέσει.');
INSERT INTO doctor_media (media_id, doctor_id) VALUES ('28', 'doctor_id');
