INSERT INTO equipment_media (media_id, equipment_id) VALUES ('311', 'equipment_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_ipsam.jpg', 'Έγραψες δυστυχής ώρα εκτός. Ναι μαγικά μιας λοιπόν διασφαλίζεται ρουτίνα σας έξι. Κώδικάς γιαυτό αλγόριθμου. Συγκεντρωμένοι τρόπο σε ποια.');
