INSERT INTO media (path, description) VALUES ('/media/images/image_voluptatem.png', 'Δοκιμάσεις λιγότερο τις εντολές συγχωνευτεί των εκθέσεις τεκμηριώνει. Εκτός που ορίστε μετράει εδώ.');
