INSERT INTO media (path, description) VALUES ('/media/images/image_eum.jpg', 'Σπίτι τους μη με ιδιαίτερα αντιλήφθηκαν. Στις ρωτάει εξαρτάται απαρατήρητο θέμα πετάνε πολύ. Τα συγχρόνως νέο διακοπή δυστυχώς.');
