INSERT INTO media (path, description) VALUES ('/media/images/image_nam.jpg', 'Τέλειοι σημεία πρώτης κανείς κανείς γραμμές για. Συγγραφής διορθώσεις επιδιόρθωση χαμηλός έχω παίρνουν εργάστηκε. Πλέον συνεντεύξεις διάβασε φράση στα διαπιστώνεις δείξει αποθηκευτικού.');
