INSERT INTO media (path, description) VALUES ('/media/images/image_assumenda.png', 'Μέρος χώρου διάσημα μην γραμμές εφαμοργής. Τα εφαμοργής μα. Αποφάσισε εκθέσεις δε πάντως μιας.
