INSERT INTO media (path, description) VALUES ('/media/images/image_iusto.png', 'Ήδη μα κόλπα επί ρωτάει προγραμματιστής μετράει. Κρατήσουν προκαλείς περιβάλλοντος δυστυχής εκδόσεις απίστευτα διοικητικό.
