INSERT INTO media (path, description) VALUES ('/media/images/image_officiis.jpg', 'Στις βγήκε ανά γραφικά συνεντεύξεις. Εδώ μα ακούσει παραδοτέου. Διακοπή μα θα ότι κανείς σημαντικό έστελνε.
