INSERT INTO media (path, description) VALUES ('/media/images/image_voluptatum.jpeg', 'Επιδιορθώσεις όχι κι τον. Όταν ποσοστό έχω ευκολότερο ελέγχου πετάξαμε λίγο. Μεταγλωτιστής όσο χρονοδιαγράμματος μέχρι.');
