INSERT INTO media (path, description) VALUES ('/media/images/image_officia.jpg', 'Διάσημα μπουν αναφέρονται. Χρησιμοποιούνταν βουτήξουν ημέρα που αθόρυβες. Πρόσληψη πλέον τον κάνε παίρνουν. Εκτελέσεις σωστά ταξινομεί σου κειμένων του.');
