INSERT INTO media (path, description) VALUES ('/media/images/image_minima.jpg', 'Πολύ συνεντεύξεις ωραίο προσπαθούν. Εκτός σωστά συγχρόνως επενδυτής διακοπής. Του βαθμό μεταφραστής στα βαθμό πολύ πετάνε βιβλίο.
