INSERT INTO media (path, description) VALUES ('/media/images/image_eaque.png', 'Τρόποι κοιτάζοντας πάρεις. Ξέχασε αναφορά πιο επενδυτής ημέρα. Λοιπόν δούλευε λαμβάνουν εδώ διαπιστώνεις. Ημέρα τις την χώρου προσοχή.');
