INSERT INTO media (path, description) VALUES ('/media/images/image_fugit.jpeg', 'Αποφάσισε από πολύ εκτός κάνεις θυμάμαι πηγαίου. Παραπάνω αναφέρονται αρέσει βαθμό ναι ανά φράση διευθυντές. Λέει κι ο κόψεις μεταγλωτιστής το για.');
INSERT INTO equipment_media (media_id, equipment_id) VALUES ('334', 'equipment_id');
INSERT INTO media (path, description) VALUES ('/media/images/image_porro.png', 'Κι και σπίτι λαμβάνουν ροή τις ένας. Σαν ναι ένας σε άτομο ημέρα εργαζόμενοι τα.
