INSERT INTO media (path, description) VALUES ('/media/images/image_quae.jpeg', 'Για κρατάει λιγότερο μην αναφέρονται αθόρυβες. Διακόψουμε μα εκτελείται ήδη τελειώσει. Εγώ μέγιστη πιο από άλγεβρα μέχρι τύπους.');
