INSERT INTO media (path, description) VALUES ('/media/images/image_provident.jpg', 'Άπειρα χειρότερα ορίστε ροή. Αν συγγραφείς τεσσαρών πάντως θέλεις. Άρα χειρότερα γεγονός ώρα ποσοστό.
