INSERT INTO media (path, description) VALUES ('/media/images/image_corrupti.png', 'Ο εκτελέσεις εντολές ότι τύπους εκδόσεις. Χρησιμοποίησέ βάζοντας μέρος ο τρόποι χρονοδιαγράμματα με παίρνει. Στο αντιλήφθηκαν δίνοντας επιδιόρθωση επί που.');
