INSERT INTO media (path, description) VALUES ('/media/images/image_voluptates.jpeg', 'Φακέλους σας οι μην παραγωγικής. Επεξεργασία δεδομένων ποια όσο. Μέχρι μπορούσες τρόποι σε. Πετάξαμε προϊόντα μου ως προσοχή.');
