INSERT INTO media (path, description) VALUES ('/media/images/image_quae.jpeg', 'Βρίσκονται δούλευε διορθώσεις δυστυχώς έξι. Επιδιορθώσεις ο στραβά επενδυτής. Εδώ τρόποι που νέα κανένας σαν μου. Τους δημιουργείς μάτσο.');
