INSERT INTO media (path, description) VALUES ('/media/images/image_commodi.png', 'Σου προσεκτικά σημεία υποψήφιο χρησιμοποιούνταν εργοστασίου έλεγχος. Μάλλον χρησιμοποιούνταν ωραίο άρα προβληματική ρουτίνα πετάνε. Κειμένων φίλος τα διακόψουμε μην.');
