INSERT INTO media (path, description) VALUES ('/media/images/image_illum.jpg', 'Πλέον φακέλους χαρακτηριστικό αρχεία πάντα προσπαθούν θέμα. Προσπαθήσεις λετπά δεν έρθει οι. Μετρήσεις χειρότερα μεταφραστής. Επιδιόρθωση θα απαρατήρητο προσλάμβανες στο πήρε.');
