INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('1', '79867', '1959-01-20 00:00:00', '1959-01-21 00:00:00', 'Σίγουρος τρέξει μια φράση εξακολουθεί. Ήδη μάθε εκτελέσει σωστά προκύπτουν. Πολύ δουλεύει κοιτάζοντας χαρακτηριστικών αυτός χρησιμοποιούσες μια κάνε.', 'Όσο εικόνες προβληματική βιβλίο για έστειλε μιας προσοχή.');
