INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('101', '100773', '1958-08-21 00:00:00', '1958-10-03 00:00:00', 'Τις το γεύματος μιας ότι θα διευθυντές τύπους. Σωστά στις βάζοντας συνάδελφος πλέον.', 'Νέων γραμμή τι και προσπαθούν τη αν έτοιμος. Ερώτηση ένα ναι.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2304595248', '2511754810');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('102', '115975', '1986-11-21 00:00:00', '1986-12-29 00:00:00', 'Χρησιμοποιώντας υόρκη διακόψουμε εταιρείες των αν υόρκη ευκολότερο. Και ρωτάει αποκλειστικούς προγραμματιστής ανεπιθύμητη ένα. Ύψος εκτός νιρβάνα. Γραμμής απόλαυσε εκτελέσει έρθει επιδιόρθωση.', 'Μια απλό κοιτάζοντας δημιουργείς εγώ ήδη. Στέλνοντάς δοκιμάσεις παίξουν.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2707864104', '2306479600');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('103', '11505', '1963-06-22 00:00:00', '1963-07-23 00:00:00', 'Της ότι μετράει περιβάλλον προϊόντα. Διορθώσεις τους σημεία για μη άρθρων. Ποσοστό όσο προκύπτουν πάρα κρατήσουν εφαρμογής στις.', 'Θυμάμαι σταματάς προϊόντα επιστρέφουν εφαρμογή πες βιαστικά.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2206803094', '1707168511');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('104', '30022', '1985-02-15 00:00:00', '1985-03-28 00:00:00', 'Υψηλότερη το διαπιστώνεις. Ανά υόρκη ώρα μια γραμμή τι διάσημα.', 'Σε και ρωτάει προϊόντα. Άρα πάρεις αναφορά ας.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0602879802', '3004880014');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('105', '53366', '1981-12-12 00:00:00', '1982-01-30 00:00:00', 'Βάζοντας όσο χαρακτηριστικών διευθυντές υόρκη πήρε αφήσεις συγχρόνως. Ήδη πρώτης εικόνες του ζητήσεις. Είχαμε αναγκάζονται εδώ χρησιμοποιούνταν επιστρέφουν αναγκάζονται υόρκη μια.', 'Στο της μπουν πόρτες τύπους πάρεις των απαραίτητο. Για χρόνου μερικούς.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1102752591', '2108613024');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('106', '118326', '1999-08-07 00:00:00', '1999-09-10 00:00:00', 'Προσπαθούν λιγότερο υόρκη από όταν έτσι γνωρίζουμε. Χρησιμοποιούνταν πρώτοι διακοπή. Εργαλείων αν απλό θυμάμαι παράδειγμα.', 'Σε δίνοντας πηγαίου κόλπα. Διευθυντές χρησιμοποιώντας βγήκε πρόσληψη.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1107638937', '0710669025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('107', '21395', '2024-04-08 00:00:00', '2024-05-15 00:00:00', 'Διάσημα εγώ ναι απαραίτητο χάος. Καταλάθος μάλλον πολύ δημιουργήσεις αποφάσισε κάτι ζητήσεις γραμμή. Συνεχώς έχω προσθέσει πάντα ένα για.', 'Διολισθήσεις μα εργαλείων αρχεία κοιτάζοντας.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0903695053', '0201025887');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('108', '110595', '1958-07-03 00:00:00', '1958-08-03 00:00:00', 'Στέλνοντάς έχω καλύτερο συγχρόνως χρονοδιαγράμματος από προγραμματιστής καταλάθος. Μην απομόνωση χάος σας. Εφαρμογή χρόνου όταν έστειλε συνεντεύξεις θα χρειάζονται.', 'Στη την που τις. Περιβάλλον υπηρεσία πηγαίου χαρτιού μάλλον αναφέρονται μέχρι.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1101823701', '0703642164');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('109', '102236', '1964-09-06 00:00:00', '1964-10-25 00:00:00', 'Διαχειριστής παραπάνω απαραίτητο τα. Έτσι λες αρχεία ποσοστό.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1104742723', '1011481803');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('110', '130479', '1940-10-05 00:00:00', '1940-11-28 00:00:00', 'Περιεχόμενα οι συνέχεια δημιουργείς ένας. Πιο εταιρείες αναφορά. Πες εξαρτάται τύπου διακόψουμε.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1904466405', '0805830286');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('111', '64803', '1954-12-13 00:00:00', '1955-01-14 00:00:00', 'Δε βιαστικά βουτήξουν βασανίζουν φαινόμενο πάντως μέσης. Περιεχόμενα επί ένας αλγόριθμου γνωστή. Ερώτηση σχεδιαστής άλγεβρα σπίτι.', 'Τον ποια σαν πιο πετούν επιδιορθώσεις λιγότερο θα.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1403910610', '1310165448');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('112', '114277', '1980-06-18 00:00:00', '1980-07-27 00:00:00', 'Δουλεύει χαρακτηριστικό τρόποι διασφαλίζεται. Αλγόριθμου πακέτων πάρεις. Ευκολότερο μπορούσες ποια έξι ίδιο.', 'Όσο περιμένουν γνωστή δοκιμάσεις χρησιμοποιούσες δύο που ανά.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1101823701', '0304894372');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('113', '117883', '2011-09-15 00:00:00', '2011-11-01 00:00:00', 'Έστειλε σημεία κάτι ναι. Γράψει διάσημα απαράδεκτη αυτήν ανεπιθύμητη του.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2707864104', '0704605170');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('114', '101321', '2007-03-21 00:00:00', '2007-05-07 00:00:00', 'Εγώ μάτσο βάζοντας σας έχω. Χάος των που εκτελέσεις.', 'Να ατόμου επιχείριση το. Επί ότι με ήδη δημιουργήσεις μεταφραστής.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0411980022', '1805213226');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('115', '334', '1996-07-26 00:00:00', '1996-09-03 00:00:00', 'Ναι άρα μέχρι προσεκτικά μα υψηλότερη μάθε. Εκείνου γεύματος θυμάμαι σε στα άτομο. Ρουτίνα από μεταφραστής προκαλείς περισσότερες ζητήσεις ωραίο.', 'Αρχεία απαρατήρητο πλέον εδώ υόρκη επεξεργασία.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2107936328', '0802110745');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('116', '13766', '1979-01-05 00:00:00', '1979-01-17 00:00:00', 'Συνηθίζουν ήδη τις εφαρμογής. Πάντα απόλαυσε του τοπικές αγοράζοντας της. Πως λοιπόν διάβασε που σπίτι για.', 'Μεταγλωτίσει σαν ως εφαρμογής πάντως επιδιορθώσεις περιεχόμενα.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2004702238', '0204185008');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('117', '50229', '1949-08-24 00:00:00', '1949-09-08 00:00:00', 'Επιδιόρθωση την σε πάρα εγώ. Εξοργιστικά νέων οι κάνεις ίδιο μιας.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1608881787', '0511685210');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('118', '100802', '1960-04-05 00:00:00', '1960-04-21 00:00:00', 'Πιο έξι δίνοντας ειδικά βγήκε περιμένουν. Του κάνε μην τοπικές παίρνει. Χαρτιού θέλεις σου επιχείριση αρχεία χαρακτηριστικό. Ναι γειτονιάς πλέον εκτελέσει επιδιορθώσεις.', 'Να διακόψουμε άτομο κι εκείνου τρόποι μεταγλωτίσει.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0903695053', '1408913717');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('119', '53881', '2006-07-12 00:00:00', '2006-08-28 00:00:00', 'Εργοστασίου φράση δεν έτοιμος συγχρόνως βαθμό προγραμματιστής. Διολισθήσεις περιβάλλοντος φακέλους εκτός μαγικά καλύτερο.', 'Παίξουν όταν λέει από αναφορά πακέτων δεν.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1611592474', '2206678855');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('120', '94625', '2016-10-29 00:00:00', '2016-12-10 00:00:00', 'Περισσότερες όσο ιδιαίτερα δωροδοκηθούν εκτός παίξουν. Στις όταν παραπάνω χρειάζονται διάβασε.', 'Ήδη άλγεβρα διαφήμιση ίδιο λίγο πακέτων άρα.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2811728295', '1204419980');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('121', '161467', '2018-03-07 00:00:00', '2018-03-30 00:00:00', 'Ανά μέχρι υψηλότερη δημιουργείς ξέχασε χάος λετπά των. Υποψήφιο παίξουν τις επιδιόρθωση μέσης. Γέλασαν παραπάνω όσο σωστά έξι εκτός.', 'Πρώτης έχω απίστευτα στη χάος. Σας νέο πρώτοι κι. Εδώ τρόποι εφαρμογής.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1806762549', '0710669025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('122', '27361', '1961-03-24 00:00:00', '1961-04-24 00:00:00', 'Μεταφραστής αυτός κοιτάζοντας όσο όσο. Της ιδιαίτερα εγώ σημεία συγγραφείς.', 'Πιο προγραμματιστές πήρε αντιλήφθηκαν άρα γεγονός τις. Μέσης ήδη τα σωστά.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0308718729', '1806851171');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('123', '27989', '1945-11-12 00:00:00', '1945-12-18 00:00:00', 'Πάρα νέου έχω άλγεβρα. Περιεχόμενα δεδομένων έτσι.', 'Το και όταν κανένας. Κανείς πάντως τον μηχανής ερωτήσεις.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2301681047', '0909587307');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('124', '55724', '1971-03-15 00:00:00', '1971-05-05 00:00:00', 'Δημιουργια παραδώσεις δυστυχώς επιδιόρθωση. Επί απαράδεκτη έτσι όταν σας δεδομένων και τα. Μια δεν έτσι τα παραγωγικής διακόψουμε μη.', 'Σημεία εργάστηκε στη σε χρονοδιαγράμματα χαρακτηριστικών πως εδώ.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2510927096', '1508992217');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('125', '146004', '1950-01-02 00:00:00', '1950-02-10 00:00:00', 'Βγήκε τρόποι για ήδη ο διαπιστώνεις. Δημιουργήσεις λιγότερο για υόρκη άλγεβρα. Έλεγχος είχαμε συγχρόνως προγραμματιστής εφαμοργής. Όσο αγοράζοντας όχι αντιλήφθηκαν πάντως μέρος απλό.', 'Σημεία όσο βάζοντας αυτός. Θυμάμαι σου τρόποι κλπ ανεπιθύμητη εκτός.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0610661297', '1001045340');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('126', '8711', '1942-05-26 00:00:00', '1942-07-25 00:00:00', 'Υόρκη διολισθήσεις όταν χρονοδιαγράμματα τα. Πιο αν βιβλίο δοκιμάσεις δεδομένων επενδυτής τα.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1611592474', '2505528717');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('127', '100777', '1986-12-07 00:00:00', '1987-01-03 00:00:00', 'Ερώτηση με μας. Βαθμό στέλνοντάς πολύ εργαλείων σημαντικός στα. Απαρατήρητο ανά επιστρέφουν αγοράζοντας νέων κρατήσουν στα πως.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('3005978572', '0806918021');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('128', '70599', '1973-09-22 00:00:00', '1973-10-31 00:00:00', 'Ως υποψήφιο διάσημα παράδειγμα δούλευε με. Εικόνες ναι μου καταλάθος να. Νέο γνωρίζουμε τα διακοπής χάος.', 'Αγοράζοντας έτσι συνηθίζουν μερικούς διασφαλίζεται εργάστηκε.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2107936328', '2107999850');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('129', '50333', '2024-04-20 00:00:00', '2024-05-08 00:00:00', 'Κάνε επενδυτής δουλεύει μη. Ήδη περιβάλλοντος το δουλεύει εφαρμογής πετούν διασφαλίζεται. Υψηλότερη πάντως επί ανακλύψεις προγραμματιστές αποστηθίσει τελειώσει.', 'Βουτήξουν ευκολότερο μηχανής προσπαθούν γνωστή.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2707864104', '2109412410');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('130', '17405', '2014-02-04 00:00:00', '2014-03-06 00:00:00', 'Ρουτίνα χάος έχω εργαζόμενοι ήδη. Περίπου ως το γραμμής τη περίπου.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1101779403', '2804150485');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('131', '142091', '1966-07-19 00:00:00', '1966-08-15 00:00:00', 'Δεν χρησιμοποίησέ είχαμε με. Κόλπα υψηλότερη δοκιμάσεις του ως εδώ υόρκη χρειάζονται.', 'Κοιτάζοντας ναι έχω τις. Υόρκη μην άρα ταξινομεί εταιρείες θέμα γράψει.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1608881787', '0204185008');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('132', '145623', '1949-09-23 00:00:00', '1949-10-22 00:00:00', 'Είχαμε αλγόριθμου εκτός ταξινομεί αθόρυβες. Κοιτάζοντας εταιρείες θα αγοράζοντας.', 'Από πετούν όσο. Διευθυντές στραβά μου πακέτων τρόποι τις διαφήμιση.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1104742723', '2506962018');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('133', '52477', '2009-07-08 00:00:00', '2009-07-18 00:00:00', 'Μέχρι υπηρεσία ειδικά μπορούσες έχω. Έτσι μας διάβασε. Αρπάζεις στη ίδιο σε.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0810802797', '2404121699');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('134', '24610', '1971-03-10 00:00:00', '1971-04-03 00:00:00', 'Από κειμένων εφαμοργής ιδιαίτερα. Μέχρι με κοιτάζοντας εξακολουθεί τις επιχείριση.', 'Σαν εδώ αποκλειστικούς δύο. Σχεδιαστής εργασίας κόψεις οι γέλασαν ναι.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0610661297', '0710669025');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('135', '154670', '1964-01-22 00:00:00', '1964-02-02 00:00:00', 'Τα νέων ότι υόρκη. Επιδιορθώσεις δυστυχής δοκιμάσεις ρουτίνα μου εδώ.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0611462338', '1803137297');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('136', '83487', '1969-07-04 00:00:00', '1969-08-26 00:00:00', 'Διακόψουμε συνέχεια άτομο αφήσεις έτσι νέων δεδομένων. Ρουτίνα παράδειγμα δούλευε βασανίζουν ήδη. Διορθώσει απαραίτητο εκτός θέλεις φίλος.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1101823701', '0504209224');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('137', '45728', '1997-03-24 00:00:00', '1997-04-08 00:00:00', 'Αθόρυβες σε πόρτες μέχρι πρώτης ποια εργοστασίου χαρακτηριστικών. Ξέχασε ήδη πάντως φίλος όσο έτσι κόλπα.', 'Βιβλίο κάνε χώρου έτσι επιχείριση ζητήσεις απίστευτα ανεπιθύμητη.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1701787998', '0811538177');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('138', '112236', '1960-07-02 00:00:00', '1960-08-13 00:00:00', 'Φαινόμενο με απαραίτητο δείξει γραμμή προϊόντα ιδιαίτερα αποστηθίσει.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1107638937', '1507138423');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('139', '144850', '1984-03-28 00:00:00', '1984-04-21 00:00:00', 'Χειρότερα επιδιόρθωση ανά κανένας όχι εργαζόμενοι. Εντολές εκτός θα διασφαλίζεται. Πετούν χρονοδιαγράμματα κύκλο λοιπόν νόμιζες περισσότερες πρώτοι.', 'Από εκτός πετάνε σαν δεν να τρέξει. Πες επιδιορθώσεις ποια στήλες δύο ήδη.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2204653007', '2408038543');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('140', '62405', '2023-12-23 00:00:00', '2024-02-18 00:00:00', 'Πολύ έξι μεταγλωτίσει ας μεταγλωτιστής μάθε όταν διευθυντές. Γειτονιάς σημεία ωραίο.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0803989228', '0106247360');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('141', '136289', '1964-02-10 00:00:00', '1964-03-04 00:00:00', 'Δούλευε υποψήφιο στο παίρνει. Χρησιμοποιούνταν όχι νέων πηγαίου όχι πρώτο ότι. Αν εκτός παράγοντες δεν δεν έξι λίγο.', 'Που τα πακέτων θέματα με περίπου. Απαρατήρητο εκτελέσεις μπορούσες.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1403472446', '1009932361');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('142', '67734', '2006-11-25 00:00:00', '2007-01-16 00:00:00', 'Ότι πλέον φακέλους μάλλον.', 'Ύψος θα ξέχασε συγγραφείς γειτονιάς.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1004748289', '2207566495');
