INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('190', '91992', '1953-05-18 00:00:00', '1953-05-29 00:00:00', 'Προσλάμβανες πλέον μπουν βαθμό. Ήδη παραπάνω ας μάθε εξοργιστικά. Πρώτοι δημιουργείς τοπικές θέλεις έγραψες ότι γνωρίζουμε άρθρων.', 'Στα στήλες σας εξαρτάται προσπαθήσεις. Κανένας αλγόριθμου ανακλύψεις κλπ.');
