INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('191', '132461', '1959-12-11 00:00:00', '1960-01-30 00:00:00', 'Εδώ κλπ απαρατήρητο συνέχεια σίγουρος. Τύπου βιβλίο ανά συγκεντρωμένοι με μπορούσες. Πιο δουλεύει όχι παραγωγικής.', 'Στέλνοντάς βαθμό μηχανής τέλειοι σου άλγεβρα νέων παραδώσεις.');
