INSERT INTO prescription (doctor_id, patient_id) VALUES ('0411550543', '2405442526');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('199', '80731', '1982-02-24 00:00:00', '1982-03-03 00:00:00', 'Ατόμου τα κι επιχείριση. Προβληματική αντιλήφθηκαν δωροδοκηθούν ναι.', 'Χρησιμοποιούσες αγοράζοντας εκτός μεταγλωτίσει.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0111647658', '3108433042');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('200', '23618', '1947-04-12 00:00:00', '1947-05-21 00:00:00', 'Ατόμου ρωτάει εργάστηκε ίδιο εκτός κόλπα εφαρμογής. Δούλευε φακέλους κανένας αγοράζοντας συνάδελφος. Σημεία άτομο έχω άρα συγγραφής.', 'Εκτός τις έξι χαμηλός διαφήμιση. Προβληματική καλύτερο κάτι μου τελειώσει.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0909662577', '0106247360');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('201', '138940', '1991-04-15 00:00:00', '1991-04-29 00:00:00', 'Αναγκάζονται γέλασαν θυμάμαι υόρκη μερικούς χρειάζονται. Ναι όταν τη ανταγωνιστής μέγιστη.', 'Ιδιαίτερα μηχανής εκείνου αναγκάζονται κώδικα σαν τρόπο.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0410505068', '2109412410');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('202', '30503', '1992-05-11 00:00:00', '1992-06-09 00:00:00', 'Κανένας εδώ λες από κύκλο έτσι διαπιστώνεις. Παραγωγικής προσπαθούν εκτελέσει τις όσο μέχρι μην.', 'Γνωστή απαράδεκτη στραβά ατόμου. Γραμμή εξοργιστικά αν ίδιο.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2203718551', '2901243442');
