INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('209', '48354', '1986-07-25 00:00:00', '1986-09-14 00:00:00', 'Λιγότερο άρθρων παραγωγικής κανείς προσπαθήσεις πετάνε απαράδεκτη. Διαδίκτυο νιρβάνα εικόνες γεύματος. Υποψήφιο αγοράζοντας μέχρι έστελνε σας.', 'Τεκμηριώνει προκαλείς μερικούς μέχρι παράγοντες κοιτάζοντας.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1107638937', '2511134275');
