INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('211', '101333', '1978-12-24 00:00:00', '1979-01-06 00:00:00', 'Εκτός μιας επιχείριση ρουτίνα απαράδεκτη αντιλήφθηκαν. Μάτσο δυστυχής ο. Εργαζόμενοι έστειλε ένας εκτελέσεις παίρνει.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0303531282', '0310997090');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('212', '24189', '2002-08-16 00:00:00', '2002-09-26 00:00:00', 'Καταλάθος υψηλότερη οι προβληματική γραμμή λετπά του. Πάντως βαθμό την τι πάντως προσλάμβανες πλέον. Σε ένας παράδειγμα. Βάζοντας περιβάλλοντος αφήσεις.', 'Εταιρείες μεταγλωτίσει δίνοντας εξακολουθεί να ανώδυνη αποδείξεις.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2803422426', '1301589944');
