INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('216', '16586', '2003-06-04 00:00:00', '2003-07-13 00:00:00', 'Εξοργιστικά σπίτι θα λέει. Εργάστηκε έτοιμος το μετρήσεις. Σταματάς προγραμματιστές οι τα.', 'Μας εντολές ατόμου διάσημα είχαμε παραπάνω τρόποι χρησιμοποιούσες.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0410505068', '1107877340');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('217', '53776', '1984-04-26 00:00:00', '1984-05-10 00:00:00', 'Μάλλον δύο δε υποψήφιο. Ελέγχου κανόνα ελέγχου αθόρυβες θυμάμαι.', 'Δε εγώ ανά κόψεις εφαρμογής ας. Με τον κάτι έχω εγώ μα. Πλέον άπειρα στη και.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0803989228', '2408038543');
