INSERT INTO prescription (doctor_id, patient_id) VALUES ('0803989228', '0502063230');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('220', '38618', '1947-06-18 00:00:00', '1947-08-07 00:00:00', 'Εκδόσεις κειμένων προβληματική διορθώσεις πιο. Πάντως πολύ πολύ. Διαδίκτυο χρησιμοποιώντας εργασίας εργασίας ο εκτός γραφικά.', 'Εικόνες διαχειριστής χαρτιού εξαρτάται τη. Θα έτοιμος σαν.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1210671054', '2302464670');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('221', '28188', '1963-11-18 00:00:00', '1964-01-10 00:00:00', 'Κι στη μη πως μέχρι στη προγραμματιστές. Όχι ανά πως κάνεις. Πακέτων κώδικάς προσλάμβανες επιστρέφουν έρθει πεδία ναι.', 'Να προκύπτουν να όταν περιμένουν δυστυχώς φράση.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('0810802797', '2607069738');
