INSERT INTO prescription (doctor_id, patient_id) VALUES ('2001691929', '1805213226');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('223', '57430', '1985-12-17 00:00:00', '1985-12-23 00:00:00', 'Να τη δωροδοκηθούν μετράει παίρνει τις διευθυντές. Ας συνάδελφος τον γεγονός εξοργιστικά. Έρθει στις στη εντολές μια την δύο. Στις γράψει σημαντικός εκείνου προσεκτικά απομόνωση νέα.', 'Σίγουρος πάντα ίδιο τη παίρνει ειδικά ζητήσεις επεξεργασία.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2203633666', '0703642164');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('224', '90526', '2024-08-23 00:00:00', '2024-08-27 00:00:00', 'Διάσημα και ποσοστό ένα. Και εκτός συνεντεύξεις τι γεγονός χαρακτηριστικών.', 'Συγχρόνως πολύ βρίσκονται παράγοντες πιο φράση πεδία.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1904466405', '2803250365');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('225', '152411', '1969-01-10 00:00:00', '1969-03-11 00:00:00', 'Εκείνου ίδιο λίγο θα αντιλήφθηκαν μιας έχω. Ύψος κάνεις τρόπο εκτός θέλεις μα. Προβληματική μεταφραστής ίδιο όχι εκείνου διάσημα μη.', 'Τι ώρα εκτός άρα δημιουργια επί.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1210671054', '1011481803');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('226', '144294', '1956-07-30 00:00:00', '1956-09-11 00:00:00', 'Διαδίκτυο πάντως γιαυτό μεταγλωτίσει γνωρίζουμε ευκολότερο. Μάθε θέλεις κανένας γραφικά τα.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('2203633666', '0312807182');
