INSERT INTO prescription (doctor_id, patient_id) VALUES ('1905740744', '1611650031');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('228', '48956', '2009-11-12 00:00:00', '2009-12-18 00:00:00', 'Μεταφραστής τοπικές μην τύπου στέλνοντάς για δε. Κοιτάζοντας μη εγώ κανόνα. Παράδειγμα δημιουργήσεις ποια κώδικάς.
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1210608936', '1604088752');
INSERT INTO prescribed_products (prescription_id, pharm_prod_id, start_date, end_date, dosage, frequency) VALUES ('229', '67041', '2009-07-29 00:00:00', '2009-09-17 00:00:00', 'Όσο γνωστή ίδιο μηχανής εκτελέσεις. Χρησιμοποίησέ βασανίζουν στραβά λιγότερο ερωτήσεις ο.', 'Επί ήδη χρησιμοποιώντας κι επιστρέφουν απαράδεκτη.');
INSERT INTO prescription (doctor_id, patient_id) VALUES ('1604612218', '0101804896');
